// Generate personalized cover letter for each job
const items = $input.all();
const coverLetters = [];

for (const item of items) {
  const jobTitle = item.json['Job-Titel'] || '';
  const company = item.json['Firma'] || 'Ihr Unternehmen';
  const description = (item.json['Beschreibung'] || '').toLowerCase();
  const score = item.json['Score'] || 5;

  // Analyze job requirements
  const isAzure = description.includes('azure');
  const isDevOps = description.includes('devops') || description.includes('ci/cd');
  const isZeroTrust = description.includes('zero trust') || description.includes('zero-trust');
  const isAI = description.includes('ai') || description.includes('copilot') || description.includes('künstliche intelligenz');
  const isKubernetes = description.includes('kubernetes') || description.includes('container');
  const isSIEM = description.includes('siem') || description.includes('security information');
  const isCompliance = description.includes('iso 27001') || description.includes('bsi') || description.includes('compliance');

  // Build personalized cover letter
  let coverLetter = `Sehr geehrte Damen und Herren,\n\n`;
  coverLetter += `mit großem Interesse habe ich Ihre Stellenausschreibung für die Position "${jobTitle}" gelesen.\n\n`;

  coverLetter += `Als Cloud-Security-Spezialist mit umfangreicher Weiterbildung in Cybersecurity, Microsoft Security Essentials und Generative AI bringe ich genau die Expertise mit, die Sie suchen. `;

  // Customize based on job requirements
  if (isAzure) {
    coverLetter += `Meine fundierte Erfahrung mit Azure Security und nativen Cloud-Security-Lösungen `;
  } else {
    coverLetter += `Meine praktische Erfahrung mit Cloud-Security (Azure, AWS) `;
  }

  coverLetter += `ermöglichen es mir, Zero-Trust-Konzepte und Security-in-Depth-Strategien erfolgreich umzusetzen.\n\n`;

  coverLetter += `Meine Qualifikationen umfassen:\n`;

  // Skill 1: Cloud Security & DevSecOps (always)
  coverLetter += `• Cloud Security & DevSecOps: Integration von Sicherheitsrichtlinien in CI/CD-Pipelines`;
  if (isDevOps) {
    coverLetter += `, praktische Projekterfahrung mit GitHub Actions und automatisierten Security-Tests`;
  }
  coverLetter += `\n`;

  // Skill 2: AI or Microsoft Security
  if (isAI) {
    coverLetter += `• AI-gestützte Security: Microsoft Security Copilot Zertifizierung und praktische Erfahrung mit KI-Agenten für automatisierte Incident Response und Threat Detection\n`;
  } else {
    coverLetter += `• Microsoft Security: Zertifizierungen in Microsoft Security Essentials und Security Copilot`;
    if (isCompliance) {
      coverLetter += `, fundierte Kenntnisse von ISO 27001, BSI C5 und Compliance-Frameworks`;
    }
    coverLetter += `\n`;
  }

  // Skill 3: DevSecOps or Container Security
  if (isKubernetes) {
    coverLetter += `• Container & Kubernetes Security: Erfahrung mit Container-Sicherheit, Image-Scanning und Security-Policies in Kubernetes-Umgebungen\n`;
  } else if (isDevOps) {
    coverLetter += `• DevSecOps-Integration: Praktische Projekterfahrung mit GitHub Actions, Threat Modelling, Security-Automatisierung und SonarQube\n`;
  } else {
    coverLetter += `• Sicherheitsanalyse & Monitoring: Threat-Modelling, Risikoanalysen`;
    if (isSIEM) {
      coverLetter += `, Erfahrung mit SIEM-Lösungen und Security-Monitoring`;
    }
    coverLetter += `\n`;
  }

  // Skill 4: Communication (always)
  coverLetter += `• Kommunikation & Teamarbeit: Deutsch (C1), Englisch (Business-Level) und ausgeprägte Teamfähigkeit für die effektive Zusammenarbeit mit DevOps- und Entwicklungsteams\n\n`;

  // Project experience
  coverLetter += `In aktuellen Projekten habe ich bereits `;
  if (isDevOps) {
    coverLetter += `CI/CD-Sicherheitsintegration mit SonarQube und GitHub Actions realisiert`;
  } else {
    coverLetter += `Security-Konzepte für Cloud-Infrastrukturen entwickelt`;
  }
  if (isAI) {
    coverLetter += ` sowie AI-gestützte Prototypen für schnellere Incident Response und intelligente Threat-Detection entwickelt.\n\n`;
  } else {
    coverLetter += ` und Zero-Trust-Architekturen implementiert.\n\n`;
  }

  // Closing
  if (score >= 8) {
    coverLetter += `Die in Ihrer Stellenausschreibung beschriebenen Aufgaben entsprechen exakt meinen Interessen und Qualifikationen. `;
  }
  coverLetter += `Gerne überzeuge ich Sie in einem persönlichen Gespräch von meiner Motivation und meinen Fähigkeiten.`;
  if (description.includes('remote') || description.includes('hybrid')) {
    coverLetter += ` Die Möglichkeit zur Remote-Arbeit schätze ich sehr und habe bereits erfolgreich in verteilten Teams gearbeitet.`;
  }
  coverLetter += `\n\n`;

  coverLetter += `Ich freue mich auf Ihre Rückmeldung!\n\n`;
  coverLetter += `Mit freundlichen Grüßen\n`;
  coverLetter += `Alexander Kölnberger\n`;
  coverLetter += `Telefon: 0160 9223 4709\n`;
  coverLetter += `E-Mail: alexanderkoelnberger@gmail.com`;

  coverLetters.push({
    json: {
      ...item.json,
      'Anschreiben': coverLetter,
      'Status': 'BEREIT',
      'Generiert am': new Date().toISOString()
    }
  });
}

return coverLetters;
